### 4. Form Handling with React Hook Form + Zod
```tsx
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";

const invoiceSchema = z.object({
  customer_id: z.number().min(1, "Customer is required"),
  currency: z.string().min(3).max(3),
  subtotal: z.string().regex(/^\d+\.\d{2}$/),
});

type InvoiceFormData = z.infer<typeof invoiceSchema>;

export function InvoiceForm() {
  const form = useForm<InvoiceFormData>({
    resolver: zodResolver(invoiceSchema),
    defaultValues: { currency: "USD" },
  });

  const onSubmit = async (data: InvoiceFormData) => {
    const result = await createInvoice(data);
    if (result.success) {
      toast.success("Invoice created");
    }
  };

  return <form onSubmit={form.handleSubmit(onSubmit)}>...</form>;
}
```

### 5. API Client Pattern
```tsx
// src/lib/api/finance.ts
import { apiClient } from "@/lib/api-client";
import type { Invoice, InvoiceCreateData } from "@/types/finance";

export async function fetchInvoices(): Promise<Invoice[]> {
  const response = await apiClient.get("/api/finance/invoices/");
  return response.data;
}

export async function createInvoice(
  data: InvoiceCreateData
): Promise<{ success: boolean; data?: Invoice; errors?: any }> {
  try {
    const response = await apiClient.post("/api/finance/invoices/", data);
    return { success: true, data: response.data };
  } catch (error: any) {
    return { success: false, errors: error.response?.data?.errors };
  }
}
```

