### Edit Form Handling

**CRITICAL**: Forms must respect lifecycle status.

```tsx
export function InvoiceForm({ invoice }: { invoice: Invoice }) {
  const isEditable = invoice.lifecycle_status === 'OPEN';

  if (!isEditable) {
    return (
      <div className="p-4 bg-yellow-50 border border-yellow-200 rounded">
        <p className="text-yellow-800">
          This invoice is {invoice.lifecycle_status} and cannot be edited.
          Please unlock it first to make changes.
        </p>
      </div>
    );
  }

  // Show edit form only if OPEN
  return <form>...</form>;
}
```

