### Manager Verification Queue

Create dedicated views for pending verifications:

```tsx
// app/(privileged)/approvals/page.tsx
export default async function ApprovalsPage() {
  const pendingTransactions = await fetchPendingVerifications();

  return (
    <div>
      <h1>Pending Verifications</h1>

      {pendingTransactions.map((txn) => (
        <div key={txn.id} className="border rounded p-4">
          <div className="flex items-center justify-between">
            <div>
              <p className="font-semibold">{txn.type} #{txn.number}</p>
              <LifecycleBadges
                lifecycleStatus={txn.lifecycle_status}
                currentLevel={txn.current_level}
                requiredLevels={txn.required_levels}
              />
            </div>

            <LifecycleActions
              model={txn.model}
              instanceId={txn.id}
              transactionType={txn.transaction_type}
              lifecycleStatus={txn.lifecycle_status}
              currentLevel={txn.current_level}
              requiredLevels={txn.required_levels}
              allowOverride={true}
              isManager={true}
              onSuccess={() => router.refresh()}
            />
          </div>
        </div>
      ))}
    </div>
  );
}
```

